window.__QUIZ_DATA__=[{"id":"objective>Commerce>2011>1","subject":"Commerce","year":"2011","type":"Objective","topic":"BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES","question":"When the government gives up its ownership and control of a business to individuals, this is known as","images":[],"options":{"A":"nationalization","B":"commercialization","C":"privatization","D":"indigenization"},"answer":"C","explanation":"Privatization is the process by which a government-owned business or property becomes owned by private, non-government parties. This process can involve either selling government-owned property or businesses to private individuals or allowing the private sector to engage in functions that were previously controlled by the government. Therefore, the correct answer is 'privatization'.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>2","subject":"Commerce","year":"2011","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT","question":"The reward received by a party in a correct agreement is known as","images":[],"options":{"A":"consideration","B":"acceptance","C":"offer","D":"warranty"},"answer":"A","explanation":"In contract law, consideration is the benefit that each party gets or expects to get from the contractual deal. It is an essential element for the formation of a contract. It can be anything of value, such as an item or a service, which each party gives as a sign of agreement to the terms of the contract. Therefore, the correct answer is 'consideration'.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>3","subject":"Commerce","year":"2011","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION","question":"Payment to a ship owner for carrying one's cargo is","images":[],"options":{"A":"demurrage","B":"fare","C":"dock due","D":"freight"},"answer":"D","explanation":"Freight is the term used to describe the cost of transporting goods from one place to another by any mode of transport, including sea, air, or land. The payment made to a ship owner for carrying one's cargo is referred to as 'freight'. Therefore, the correct answer is 'freight'.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>4","subject":"Commerce","year":"2011","type":"Objective","topic":"ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE","question":"Which of the following is not pre-sale service?","images":[],"options":{"A":"Repair and maintenance work","B":"Providing detailed information about the goods to be purchased","C":"Demonstrating the use and performance of the product to be sold","D":"Setting up facilities for storing the product to be bought"},"answer":"A","explanation":"Pre-sale services are those services that are provided before the purchase of the product. Repair and maintenance work is a post-sale service, not a pre-sale service.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>5","subject":"Commerce","year":"2011","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE","question":"Which of the following is used to inform the addressee that he has a registered parcel for collection?","images":[],"options":{"A":"Counterfoil","B":"Express label","C":"Slip","D":"Telegram"},"answer":"C","explanation":"A slip is typically left at the addressee's address to inform them of a registered parcel for collection.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>6","subject":"Commerce","year":"2011","type":"Objective","topic":"BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES","question":"The co-operative society that perform a combination of the function of other types of cooperative is called","images":[],"options":{"A":"consumer cooperative","B":"multipurpose cooperative","C":"producer cooperative","D":"thrift and credit cooperative"},"answer":"B","explanation":"A multipurpose cooperative is a type of co-operative society that performs a combination of the functions of other types of cooperatives.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>7","subject":"Commerce","year":"2011","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE","question":"That portion of the share capital which the company has asked the shareholders to pay for is known as","images":[],"options":{"A":"authorised capital","B":"paid-up capital","C":"issued capital","D":"called-up capital"},"answer":"D","explanation":"Called-up capital is the portion of share capital that a company has asked its shareholders to pay. Authorised capital is the maximum amount of share capital that a company can issue. Paid-up capital is the amount of money a company has received from shareholders in exchange for shares. Issued capital is the total value of the shares that a company has issued.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>8","subject":"Commerce","year":"2011","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION","question":"One of the advantages of air transport over other forms of transport is","images":[],"options":{"A":"safety","B":"flexibility","C":"cost","D":"speed"},"answer":"D","explanation":"Air transport is significantly faster than other forms of transport, especially for long distances. Safety, flexibility, and cost are also factors, but they are not the primary advantage of air transport. Safety can vary depending on the specific circumstances, flexibility is limited by factors such as airport locations and flight schedules, and cost is generally higher for air transport compared to other forms.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>9","subject":"Commerce","year":"2011","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT","question":"Which of the following are elements of valid contract?","images":[],"options":{"A":"Discharge and performance","B":"Offer and acceptance","C":"Age and maturity","D":"Promise and capacity"},"answer":"B","explanation":"The elements of a valid contract include offer and acceptance, intention to create legal relations, consideration, capacity to contract, and legality of the object. Discharge and performance are stages in the life of a contract, not elements of a contract. Age and maturity relate to the capacity to contract, but they are not elements in themselves. Promise and capacity are also related to contract formation, but they are not standalone elements.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>10","subject":"Commerce","year":"2011","type":"Objective","topic":"TRADE : HOME TRADE: RETAIL TRADE","question":"The last link in the channel of distribution is the","images":[],"options":{"A":"retailer","B":"consumer","C":"wholesaler","D":"producer"},"answer":"B","explanation":"The last link in the channel of distribution is the consumer. The channel of distribution refers to the path or route along which goods move from producers or manufacturers to ultimate consumers or industrial users. It starts with the producer and ends with the consumer.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>11","subject":"Commerce","year":"2011","type":"Objective","topic":"TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.","question":"Taxes on imported foreign goods are known as","images":[],"options":{"A":"excise duties","B":"tariffs","C":"ad valorem taxes","D":"dock dues"},"answer":"B","explanation":"Taxes on imported foreign goods are known as tariffs. Tariffs are a type of tax imposed on imported goods (and sometimes exported goods) by the domestic government. They are used to increase the price of imported goods and services, making them more expensive for consumers and thus less competitive with domestic goods and services.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>12","subject":"Commerce","year":"2011","type":"Objective","topic":"TRADE : FOREIGN TRADE","question":"If Karamos who lives in The Gambia imports goods from Senegal and later sells them in Guinea Bissau: Karamo is engaged in","images":[],"options":{"A":"multi-lateral trade","B":"counter trade","C":"barter trade","D":"entrepot trade"},"answer":"D","explanation":"If Karamos who lives in The Gambia imports goods from Senegal and later sells them in Guinea Bissau, Karamo is engaged in entrepot trade. Entrepot trade is a form of international trade in which goods are imported from one country and then re-exported to another country, often after some processing or re-packaging.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>2011>13","subject":"Commerce","year":"2011","type":"Objective","topic":"TRADE : HOME TRADE: RETAIL TRADE","question":"Manufacturer may sell directly to the consumers where goods are   i. made to customer's specification   ii. advertised by the manufacturer   iii.perishable   iv. highly technical.","images":[],"options":{"A":"I, III and IV only","B":"I and III only","C":"III, IV and V only","D":"III and IV only"},"answer":"A","explanation":"Manufacturers may sell directly to consumers when goods are made to customer's specification, are perishable, or are highly technical. This is because these types of goods often require direct interaction between the manufacturer and the consumer. Goods made to customer's specification need direct interaction to ensure the product meets the customer's needs. Perishable goods need to be sold quickly, which can often be done more efficiently by the manufacturer. Highly technical goods may require the manufacturer's knowledge to explain and sell the product.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>14","subject":"Commerce","year":"2011","type":"Objective","topic":"MONEY : MEANING AND TYPES OF MONEY","question":"Which of the following is a means of payment?","images":[],"options":{"A":"I.O.U","B":"Postal order","C":"Promissory note","D":"C.I.F"},"answer":"B","explanation":"A postal order is a means of payment. It is a financial instrument usually intended for sending money through the mail. It is purchased at a post office and is payable at another post office to the named recipient. An I.O.U is a document that acknowledges a debt but it is not a means of payment. A promissory note is a financial instrument that contains a written promise by one party to pay another party a definite sum of money either on demand or at a specified future date. A promissory note typically contains all the terms pertaining to the indebtedness, such as the principal amount, interest rate, maturity date, date and place of issuance, and issuer's signature. CIF (Cost, Insurance, and Freight) is a term used in international trade for the point at which responsibility for goods transfers from the seller to the buyer.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>2011>15","subject":"Commerce","year":"2011","type":"Objective","topic":"TRADE : FOREIGN TRADE","question":"Shipping services rendered by Nigeria to The Gambia would be classified by The Gambia as","images":[],"options":{"A":"invisible imports","B":"invisible exports","C":"visible imports","D":"visible export"},"answer":"A","explanation":"Shipping services rendered by Nigeria to The Gambia would be classified by The Gambia as invisible imports. In the balance of payments, invisible imports are services bought from foreign countries. These services do not result in the physical movement of tangible goods and are not visible. They include services like transportation, banking, insurance, tourism, and technology.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>16","subject":"Commerce","year":"2011","type":"Objective","topic":"PRODUCTION : FACTORS OF PRODUCTION","question":"The main division of production are","images":[],"options":{"A":"industry, direct and indirect services","B":"extraction, manufacturing and construction","C":"industry, commerce and direct services","D":"industry, commerce and trading"},"answer":"B","explanation":"The main divisions of production are extraction, manufacturing, and construction. These are the primary stages of production where raw materials are extracted, then manufactured into goods, and finally, construction involves building infrastructure.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>17","subject":"Commerce","year":"2011","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER","question":"A trader's turnover was D36,000. Purchases was D28,000. The opening stock was D2,000 and the closing stock D3,000.  What is the cost of goods sold?","images":[],"options":{"A":"D28,000","B":"D27,000","C":"D8,000","D":"D5,000"},"answer":"B","explanation":"The cost of goods sold (COGS) is calculated by adding the opening stock and purchases, then subtracting the closing stock. In this case, COGS = D28,000 (Purchases) + D2,000 (Opening Stock) - D3,000 (Closing Stock) = D27,000.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>2011>18","subject":"Commerce","year":"2011","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER","question":"A trader's turnover was D36,000. Purchases was D28,000. The opening stock was D2,000 and the closing stock D3,000.  The average stock is","images":[],"options":{"A":"D5,000","B":"D3,000","C":"D2,500","D":"D2,000"},"answer":"C","explanation":"The average stock is calculated by adding the opening and closing stock and dividing by 2.     In this case, Average Stock = (D2,000 (Opening Stock) + D3,000 (Closing Stock)) / 2     = D2,500.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>2011>19","subject":"Commerce","year":"2011","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER","question":"A trader's turnover was D36,000. Purchases was D28,000. The opening stock was D2,000 and the closing stock D3,000. What is the rate of turnover?","images":[],"options":{"A":"13.5 times","B":"10.8 times","C":"9 times","D":"5.4 times"},"answer":"B","explanation":"The rate of turnover is calculated by dividing the cost of goods sold by the average inventory. The cost of goods sold is calculated by adding the opening stock to purchases and then subtracting the closing stock. In this case, the cost of goods sold is D36,000 + D28,000 - D3,000 = D61,000. The average inventory is the average of the opening and closing stock, which is (D2,000 + D3,000) / 2 = D2,500. Therefore, the rate of turnover is D61,000 / D2,500 = 10.8 times.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>2011>20","subject":"Commerce","year":"2011","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : TYPES","question":"In marine insurance when a particular cargo is thrown into the sea in order to prevent the ship from sinking, the type of marine loss is","images":[],"options":{"A":"Particular average loss","B":"general average loss","C":"total average loss","D":"constructive average loss"},"answer":"B","explanation":"In marine insurance, a general average loss refers to a loss resulting from a voluntary sacrifice of any part of the ship or cargo, or an expenditure, to safeguard the ship and the rest of its cargo. If a particular cargo is thrown into the sea to prevent the ship from sinking, it is a voluntary sacrifice made for the safety of the ship and the rest of the cargo, hence it is a general average loss.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>21","subject":"Commerce","year":"2011","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TURNOVER","question":"The turnover of a trade is the","images":[],"options":{"A":"number of times the stock is sold","B":"total sales made during a period","C":"profit made during the period","D":"total purchases made during the period"},"answer":"B","explanation":"The turnover of a trade refers to the total sales made during a period. It is the total amount of goods or services sold by a business during a certain period. It does not refer to the number of times the stock is sold, the profit made during the period, or the total purchases made during the period.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>22","subject":"Commerce","year":"2011","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL","question":"The total assets of a business less its total liability is known as","images":[],"options":{"A":"capital owned","B":"share capital","C":"issued capital","D":"working capital"},"answer":"A","explanation":"The total assets of a business less its total liability is known as capital owned. This is because the capital owned by a business is essentially the net worth of the business, which is calculated by subtracting the total liabilities from the total assets.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>23","subject":"Commerce","year":"2011","type":"Objective","topic":"STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS","question":"A document is issued to the public by a company to advertise its share is known as","images":[],"options":{"A":"prospectus","B":"tender","C":"share certificate","D":"trading certificate"},"answer":"A","explanation":"A document issued to the public by a company to advertise its share is known as a prospectus. A prospectus is a legal document that institutions and businesses use to describe the securities they are offering for participants and buyers. It provides details about the financial health of the company offering the securities.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>24","subject":"Commerce","year":"2011","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"An overdraft is the","images":[],"options":{"A":"amount permitted to be withdrawn in excess of one's deposit","B":"excess cash withdrawn by commercial banks from the Central Bank","C":"credit balance standing in the name of a customer","D":"special deposit made by commercial banks"},"answer":"A","explanation":"An overdraft is the amount permitted to be withdrawn in excess of one's deposit. It is a type of short-term loan that allows you to continue withdrawing money even if your account has no funds in it or not enough to cover the withdrawal. Banks may permit this as a form of credit to trusted customers.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>25","subject":"Commerce","year":"2011","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : PRINCIPLES","question":"Which of the following is NOT a principle of insurance?","images":[],"options":{"A":"Insurable interest","B":"Subrogation","C":"Surrender value","D":"proximate cause"},"answer":"C","explanation":"The principles of insurance include insurable interest, subrogation, and proximate cause. However, surrender value is not a principle of insurance. Surrender value is the amount the policyholder will receive from the insurance company if he/she decides to exit the policy before maturity. It is a term associated with life insurance.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>26","subject":"Commerce","year":"2011","type":"Objective","topic":"STOCK EXCHANGE : TYPES OF SECURITIES","question":"The par value of a share is also known as its","images":[],"options":{"A":"premium price","B":"market price","C":"discount price","D":"nominal price"},"answer":"D","explanation":"The par value of a share is also known as its nominal price. The par value is the face value of a bond or stock as stated by the issuer. It is the value at which the share was originally issued and it remains constant over time, regardless of the market price of the share.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>27","subject":"Commerce","year":"2011","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"A cheque dated 15th March, 2012 will become stale on","images":[],"options":{"A":"6th June, 2012","B":"16th July, 2012","C":"16th August, 2012","D":"16th September 2012"},"answer":"D","explanation":"A cheque becomes stale after a period of six months from the date written on it. Therefore, a cheque dated 15th March, 2012 will become stale on 16th September, 2012. A stale cheque is not honored by the bank.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>28","subject":"Commerce","year":"2011","type":"Objective","topic":"AIDS TO TRADE: BANKING : SERVICES & CHALLENGES","question":"Bank settle their indebtedness in the","images":[],"options":{"A":"discount house","B":"stock exchange market","C":"commercial bank","D":"clearing house"},"answer":"D","explanation":"Banks settle their indebtedness in the clearing house. A clearing house is a financial institution formed to facilitate the exchange (clearing) of payments, securities, or derivatives transactions. The clearing house stands between two clearing firms (also known as member firms or clearing participants) and its purpose is to reduce the risk of one (or more) clearing firm failing to honor its trade settlement obligations.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>29","subject":"Commerce","year":"2011","type":"Objective","topic":"TRADE : FOREIGN TRADE","question":"Which of the following distinguishes home trade from foreign trade?","images":[],"options":{"A":"Payments are easily arranged","B":"Taxes are levied","C":"Goods have to be warehoused","D":"Middlemen are not required"},"answer":"A","explanation":"The main difference between home trade and foreign trade is that in home trade, payments are easily arranged. This is because the buyer and seller are in the same country and use the same currency. In foreign trade, payments can be more complex due to differences in currency and banking regulations.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>30","subject":"Commerce","year":"2011","type":"Objective","topic":"MONEY : MEANING AND TYPES OF MONEY","question":"Before the advent of legal tender and credit instrument, which of the following was used as a medium of exchange?","images":[],"options":{"A":"Currency note","B":"Cowries","C":"Cheques","D":"Bank drafts"},"answer":"B","explanation":"Before the advent of legal tender and credit instruments, cowries were used as a medium of exchange. Cowries are a type of shell which were used as currency in some cultures. They were used in many parts of Africa, Asia, and the Americas.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>2011>31","subject":"Commerce","year":"2011","type":"Objective","topic":"PURCHASES AND SALES OF GOODS : TERMS OF TRADE","question":"When C.I.F is quoted on an invoice, it means that the price includes the","images":[],"options":{"A":"cost of goods only","B":"cost of insurance only","C":"cost of carriage only","D":"cost, insurance and carriage"},"answer":"D","explanation":"C.I.F stands for Cost, Insurance, and Freight. It is a term used in international trade that means the seller of the goods is responsible for arranging and paying for transportation of the goods to the port of destination, including the cost of insurance. Therefore, when C.I.F is quoted on an invoice, it means that the price includes the cost of the goods, the cost of insurance, and the cost of carriage.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>32","subject":"Commerce","year":"2011","type":"Objective","topic":"TRADE ASSOCIATION : MEANING & FUNCTIONS","question":"Encouraging a high quality of member's products through the circulation of research information is a function of","images":[],"options":{"A":"Manufacturers Association","B":"Trade Union","C":"Employers' Association","D":"Consumers' Association"},"answer":"A","explanation":"The function of encouraging a high quality of member's products through the circulation of research information is typically performed by a Manufacturers Association. This is because a Manufacturers Association is a group of businesses in the same industry that collaborate to promote their common interests, including the improvement of product quality and the sharing of research information.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>33","subject":"Commerce","year":"2011","type":"Objective","topic":"TRADE ASSOCIATION : CHAMBER OF COMMERCE","question":"A voluntary association of business executives within a locality is known as","images":[],"options":{"A":"Trade union","B":"consumers' Association","C":"Chamber of commerce","D":"Trade Association"},"answer":"C","explanation":"A voluntary association of business executives within a locality is known as a Chamber of Commerce. A Chamber of Commerce is a local organization of businesses whose goal is to further the interests of businesses in a locality. They often offer networking opportunities, training, and other resources to help local businesses succeed.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>34","subject":"Commerce","year":"2011","type":"Objective","topic":"TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.","question":"Which of the following is NOT a function of the ports authority?","images":[],"options":{"A":"Providing facilities for loading and off-loading of vessels","B":"Collecting dock dues","C":"Providing enough ships for the country","D":"Dredging of harbours"},"answer":"C","explanation":"The function of the ports authority is to manage and operate the ports. This includes providing facilities for loading and off-loading of vessels, collecting dock dues, and dredging of harbours. However, providing enough ships for the country is not a function of the ports authority. This is typically the responsibility of the shipping companies or the government.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>2011>35","subject":"Commerce","year":"2011","type":"Objective","topic":"ELEMENT OF MARKETING : MARKETING MIX","question":"Using symbol, letters, name or combination of these by a company to distinguish its products is","images":[],"options":{"A":"product cycle","B":"marketing mix","C":"trading mark","D":"market segmentation"},"answer":"C","explanation":"A trading mark, also known as a trademark, is a recognizable sign, design, or expression which identifies products or services of a particular source from those of others. The trademark owner can be an individual, business organization, or any legal entity. It is not a product cycle, marketing mix or market segmentation.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>36","subject":"Commerce","year":"2011","type":"Objective","topic":"TRADE : HOME TRADE: WHOLESALE TRADE","question":"Trade as a division of commerce is usually classified into","images":[],"options":{"A":"retail and wholesale","B":"import and export","C":"home and foreign","D":"visible and invisible"},"answer":"C","explanation":"Trade is divided into home or domestic or internal trade and foreign/external/international trade.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>37","subject":"Commerce","year":"2011","type":"Objective","topic":"OCCUPATION : MEANING & IMPORTANCE","question":"The box marked 'X' stands for","images":["data:image/png;base64,"],"options":{"A":"indirect services","B":"industry","C":"occupation","D":"aids to trade"},"answer":"B","explanation":"The main divisions of production: industry, commerce & direct services.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>2011>38","subject":"Commerce","year":"2011","type":"Objective","topic":"TRADE : HOME TRADE: WHOLESALE TRADE","question":"The box marked 'Y' stands for","images":["data:image/png;base64,"],"options":{"A":"wholesale","B":"direct services","C":"Aids to trade","D":"foreign trade"},"answer":"C","explanation":"The aids to trade include transport, communication, banking etc.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>2011>39","subject":"Commerce","year":"2011","type":"Objective","topic":"TRADE : FOREIGN TRADE","question":"The box marked 'Z' stands for","images":["data:image/png;base64,"],"options":{"A":"warehousing","B":"Home trade","C":"Foreign trade","D":"Marketing"},"answer":"A","explanation":"Warehousing is one of the aids to trade and it involves the act of storing goods ahead of demand.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>2011>40","subject":"Commerce","year":"2011","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE","question":"Liquid capital in a business means the","images":[],"options":{"A":"movable assets of the business","B":"authorised capital","C":"issued capital","D":"assets easily convertible to cash"},"answer":"D","explanation":"Liquid capital in a business refers to assets that can be easily converted into cash. These assets are highly liquid and can be sold or exchanged for cash without affecting their market value. This is important for businesses as it allows them to quickly access funds to meet short-term obligations or make quick investments.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>2011>41","subject":"Commerce","year":"2011","type":"Objective","topic":"BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES","question":"The \"relationship which subsists between two or more persons carrying on a business with a view of profit is","images":[],"options":{"A":"cooperative society","B":"partnership","C":"Public limited company","D":"credit union"},"answer":"B","explanation":"The statement describes a partnership. A partnership is a type of business organization where two or more individuals pool money, skills, and other resources, and share profit and loss in accordance with terms of the partnership agreement. In absence of such agreement, a partnership is assumed to exist where the participants in an enterprise agree to share the associated risks and rewards proportionately.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>42","subject":"Commerce","year":"2011","type":"Objective","topic":"STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS","question":"\"Right issues\" is the","images":[],"options":{"A":"individual's right to be issued shares on subscription","B":"right of shareholders to vote on issues","C":"preferential right to return to shares","D":"shares offered to existing shareholders at a cheaper price"},"answer":"D","explanation":"\"Right issues\" refers to the shares offered to existing shareholders at a cheaper price. This is a way for companies to raise additional equity capital. With the help of rights issues, the company asks the existing shareholders to buy additional new shares in proportion to their existing holdings.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>43","subject":"Commerce","year":"2011","type":"Objective","topic":"BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES","question":"In limited partnership the partners'","images":[],"options":{"A":"capital is limited","B":"liability is limited","C":"participation is limited","D":"ownership is unlimited"},"answer":"B","explanation":"In a limited partnership, the liability of at least one partner is limited. This means that they are only liable for the amount of capital they have invested into the business and their personal assets are not at risk. This is different from a general partnership where all partners have unlimited liability.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>44","subject":"Commerce","year":"2011","type":"Objective","topic":"PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING","question":"Which of the following pieces of information would be found in a typical debit note?","images":[],"options":{"A":"Customer code","B":"Date of invoice","C":"Brief reason for the debit","D":"E & O.E"},"answer":"C","explanation":"Debit notes usually all include the same general information: the date of the note, a serial number, a brief description of the prior business transaction, details of items returned (including sales taxes and a reference to the invoice), and the signatures of appropriate company authorities.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>45","subject":"Commerce","year":"2011","type":"Objective","topic":"TRADE : HOME TRADE: WHOLESALE TRADE","question":"The completion of the production process by grading and branding of goods is a function of the","images":[],"options":{"A":"transporter","B":"wholesaler","C":"retailer","D":"consumer"},"answer":"B","explanation":"The completion of the production process by grading and branding of goods is a function of the wholesaler. Wholesalers often sort goods into different grades, depending on their quality. They also often label the goods with their own brand or the manufacturer's brand. This is part of the value-added services that wholesalers provide.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>46","subject":"Commerce","year":"2011","type":"Objective","topic":"INTRODUCTION TO COMMERCE : MEANING & SCOPE","question":"The development of commerce was encouraged by the desire to","images":[],"options":{"A":"get goods and services to others","B":"work with others","C":"create wealth for the nation","D":"satisfy all wants and needs"},"answer":"A","explanation":"The development of commerce was primarily encouraged by the desire to get goods and services to others. Commerce involves the exchange of goods and services, and its development was driven by the need to facilitate this exchange, making goods and services available to those who need them.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>2011>47","subject":"Commerce","year":"2011","type":"Objective","topic":"ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.","question":"Which of the following countries is NOT a member of the Lake Chad Basin Commission?","images":[],"options":{"A":"Nigeria","B":"Chad","C":"Gabon","D":"Cameroun"},"answer":"C","explanation":"Gabon is not a member of the Lake Chad Basin Commission. The Lake Chad Basin Commission (LCBC) is a regional body established in May 22,1964 by Cameroon, Chad, Niger, and Nigeria. Other countries, such as the Central African Republic and Libya, joined later. However, Gabon is not a member of this commission.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>2011>48","subject":"Commerce","year":"2011","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT","question":"A false statement made by one party with an intention of inducing the other party to enter into a contract with him is known as","images":[],"options":{"A":"misrepresentation","B":"legal capacity","C":"consensus ad idem","D":"consideration"},"answer":"A","explanation":"A false statement made by one party with an intention of inducing the other party to enter into a contract with him is known as misrepresentation. Misrepresentation is a concept in contract law where a false or misleading statement is made that convinces another party to enter into an agreement. The statement could be a fact that is not true, or could be a promise made without any intention of performing it.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>2011>49","subject":"Commerce","year":"2011","type":"Objective","topic":"ELEMENT OF MARKETING : THE MARKETING CONCEPT","question":"The essence of adopting the marketing concept by a firm is the recognition that goods and services have no value unless they are","images":[],"options":{"A":"desirable to customers","B":"company oriented","C":"beautiful packaged","D":"profit oriented"},"answer":"A","explanation":"The marketing concept is a business philosophy that holds the key to achieving organizational goals consists of the company being more effective than competitors in creating, delivering, and communicating customer value to its chosen target markets. Therefore, the essence of adopting the marketing concept by a firm is the recognition that goods and services have no value unless they are desirable to customers. This is because the value of a product or service is determined by the customer's perception of its worth, not by the cost of production or the price set by the company.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>2011>50","subject":"Commerce","year":"2011","type":"Objective","topic":"LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION","question":"When consumers engage in action that express dissatisfaction with the quantity, price and quality of goods available, such action is termed","images":[],"options":{"A":"Consumer behaviour","B":"Consumerism","C":"Consumer education","D":"Consumer orientation"},"answer":"B","explanation":"Consumerism is a social and economic order that encourages the acquisition of goods and services in ever-increasing amounts. When consumers engage in action that express dissatisfaction with the quantity, price and quality of goods available, such action is termed Consumerism. This is because consumerism involves advocating for the rights and interests of consumers, including the right to information, the right to choose, the right to safety, and the right to be heard.","marks":"1","difficulty":"2"}];